import { useEffect, useState } from "react";
import Link from "next/link";

export default function AdminDashboard({ user }: { user: any }) {
  const [stats, setStats] = useState<any>(null);
  const [tarefas, setTarefas] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  // Função para carregar dados
  const fetchAllData = async () => {
    try {
      const token = localStorage.getItem("token");

      // 1. Métricas
      const resStats = await fetch("http://localhost:5000/api/v1/dashboard/admin", {
        headers: { "Authorization": `Bearer ${token}` }
      });
      const jsonStats = await resStats.json();
      if (jsonStats.success) setStats(jsonStats.data);

      // 2. Tarefas Pendentes
      const resTarefas = await fetch("http://localhost:5000/api/v1/admin/tarefas", {
        headers: { "Authorization": `Bearer ${token}` }
      });
      const jsonTarefas = await resTarefas.json();
      if (jsonTarefas.success) setTarefas(jsonTarefas.data);

    } catch (error) {
      console.error("Erro ao carregar dashboard admin", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const handleProcessar = async (id: number, acao: 'validar' | 'rejeitar' | 'liquidar') => {
    let motivo = "";
    if (acao === 'rejeitar') {
      motivo = prompt("Motivo da rejeição:") || "";
      if (!motivo) return; // Cancelou
    }

    if (!confirm(`Tem a certeza que deseja ${acao.toUpperCase()} esta operação?`)) return;

    try {
      const token = localStorage.getItem("token");
      const res = await fetch(`http://localhost:5000/api/v1/admin/transacoes/${id}/processar`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`
        },
        body: JSON.stringify({ acao, motivo })
      });

      const json = await res.json();
      if (json.success) {
        alert(json.message);
        fetchAllData(); // Atualiza as listas
      } else {
        alert(json.error || "Erro ao processar.");
      }
    } catch (e) {
      alert("Erro de conexão.");
    }
  };

  if (loading) return <div className="p-10 text-center text-gray-500">A carregar centro de comando...</div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      {/* Cabeçalho */}
      <div className="md:flex md:items-center md:justify-between mb-8">
        <div className="flex-1 min-w-0">
          <span className="inline-flex items-center px-3 py-0.5 rounded-full text-sm font-medium bg-purple-100 text-purple-800 mb-2">
            Administrador
          </span>
          <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">
            Painel de Controlo
          </h2>
        </div>
      </div>

      {/* KPIs Globais */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 mb-8">
        {[
          { label: "Utilizadores Totais", value: stats?.kpis.total_users, color: "bg-blue-500", icon: "👥" },
          { label: "Volume de Vendas", value: stats?.kpis.volume_vendas, color: "bg-green-500", icon: "💰", format: true },
          { label: "Comissões (5%)", value: stats?.kpis.comissoes, color: "bg-purple-500", icon: "📊", format: true },
          { label: "Tarefas Pendentes", value: (tarefas?.validacoes.length || 0) + (tarefas?.liquidacoes.length || 0), color: "bg-yellow-500", icon: "⚠️" }
        ].map((kpi) => (
          <div key={kpi.label} className="bg-white overflow-hidden shadow rounded-lg">
            <div className="p-5">
              <div className="flex items-center">
                <div className={`flex-shrink-0 rounded-md p-3 ${kpi.color} text-white text-xl`}>
                  {kpi.icon}
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dt className="text-sm font-medium text-gray-500 truncate">{kpi.label}</dt>
                  <dd className="text-lg font-bold text-gray-900">
                    {kpi.format
                      ? new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(kpi.value || 0)
                      : kpi.value || 0}
                  </dd>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* COLUNA 1: Validação de Pagamentos (Entrada de Dinheiro) */}
        <div className="bg-white shadow rounded-lg overflow-hidden">
          <div className="px-6 py-5 border-b border-gray-200 bg-gray-50">
            <h3 className="text-lg font-medium text-gray-900">Validar Pagamentos (Escrow)</h3>
          </div>

          {tarefas?.validacoes.length > 0 ? (
            <ul className="divide-y divide-gray-200">
              {tarefas.validacoes.map((t: any) => (
                <li key={t.id} className="p-6">
                  <div className="flex justify-between items-start">
                    <div>
                      <p className="text-sm font-medium text-gray-900">Ref: {t.ref}</p>
                      <p className="text-sm text-gray-500">Comprador: {t.comprador}</p>
                      <p className="text-sm font-bold text-green-600 mt-1">
                        {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(t.valor)}
                      </p>
                      <p className="text-xs text-gray-400 mt-1">{new Date(t.data).toLocaleDateString()}</p>
                    </div>
                    {t.comprovativo ? (
                      <a href={`http://localhost:5000${t.comprovativo}`} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:text-blue-800 text-sm underline">
                        Ver Comprovativo 📎
                      </a>
                    ) : (
                      <span className="text-red-500 text-xs">Sem anexo</span>
                    )}
                  </div>
                  <div className="mt-4 flex gap-3">
                    <button
                      onClick={() => handleProcessar(t.id, 'validar')}
                      className="flex-1 bg-green-600 text-white px-3 py-2 rounded text-sm hover:bg-green-700"
                    >
                      Aprovar
                    </button>
                    <button
                      onClick={() => handleProcessar(t.id, 'rejeitar')}
                      className="flex-1 bg-red-100 text-red-700 px-3 py-2 rounded text-sm hover:bg-red-200"
                    >
                      Rejeitar
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          ) : (
             <div className="p-8 text-center text-gray-500">Tudo validado! ✅</div>
          )}
        </div>

        {/* COLUNA 2: Liquidação ao Produtor (Saída de Dinheiro) */}
        <div className="bg-white shadow rounded-lg overflow-hidden">
          <div className="px-6 py-5 border-b border-gray-200 bg-gray-50">
            <h3 className="text-lg font-medium text-gray-900">Liquidar Produtores (Transferências)</h3>
          </div>

          {tarefas?.liquidacoes.length > 0 ? (
            <ul className="divide-y divide-gray-200">
              {tarefas.liquidacoes.map((t: any) => (
                <li key={t.id} className="p-6">
                  <div className="mb-4">
                    <p className="text-sm font-medium text-gray-900">Produtor: {t.produtor}</p>
                    <p className="text-sm text-gray-500">IBAN: <span className="font-mono bg-gray-100 px-1">{t.iban || "N/D"}</span></p>
                    <div className="mt-2 flex justify-between items-center bg-green-50 p-2 rounded">
                       <span className="text-sm text-green-800">A transferir:</span>
                       <span className="font-bold text-green-800 text-lg">
                         {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(t.valor_liquido)}
                       </span>
                    </div>
                    <p className="text-xs text-gray-400 mt-2">Comissão retida: {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(t.comissao)}</p>
                  </div>
                  <button
                    onClick={() => handleProcessar(t.id, 'liquidar')}
                    className="w-full bg-purple-600 text-white px-3 py-2 rounded text-sm hover:bg-purple-700"
                  >
                    Confirmar Transferência Realizada
                  </button>
                </li>
              ))}
            </ul>
          ) : (
             <div className="p-8 text-center text-gray-500">Nenhum pagamento pendente! 🎉</div>
          )}
        </div>

      </div>
    </div>
  );
}