"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Navbar from "@/components/Navbar";
import ProdutorDashboard from "@/components/dashboard/ProdutorDashboard";
import CompradorDashboard from "@/components/dashboard/CompradorDashboard";
import AdminDashboard from "@/components/dashboard/AdminDashboard";

export default function DashboardPage() {
  const router = useRouter();
  const [user, setUser] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Debug: Verificar o que está no localStorage
    const storedUser = localStorage.getItem("user");
    const storedToken = localStorage.getItem("token");

    if (!storedUser || !storedToken) {
      router.push("/auth/login");
    } else {
      try {
        const parsedUser = JSON.parse(storedUser);
        setUser(parsedUser);
      } catch (e) {
        console.error("Erro ao ler dados do utilizador", e);
        localStorage.removeItem("user");
        router.push("/auth/login");
      }
    }
    setLoading(false);
  }, [router]);

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="text-center">
        <div className="w-16 h-16 border-4 border-green-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
        <p className="text-gray-600 font-medium">A carregar o seu painel...</p>
      </div>
    </div>
  );

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      <main className="py-10">
        {user.tipo === "admin" ? (
          <AdminDashboard user={user} />
        ) : user.tipo === "produtor" ? (
          <ProdutorDashboard user={user} />
        ) : (
          <CompradorDashboard user={user} />
        )}
      </main>
    </div>
  );
}