"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { Menu, X, User, LogOut, ChevronDown, ShoppingBag, LayoutDashboard, HelpCircle } from 'lucide-react';

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const pathname = usePathname();
  const router = useRouter();

  // Verificar autenticação ao montar
  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    window.location.href = "/auth/login";
  };

  const isActive = (path: string) => pathname === path ? "text-green-600 font-semibold" : "text-gray-600 hover:text-green-600";

  return (
    <nav className="bg-white/95 backdrop-blur-md border-b border-gray-100 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20">

          {/* Logo */}
          <div className="flex items-center">
            <Link href="/" className="flex-shrink-0 flex items-center gap-2">
              <div className="bg-green-600 p-2 rounded-lg">
                <span className="text-white font-bold text-xl">AK</span>
              </div>
              <span className="font-bold text-2xl tracking-tighter text-gray-900">
                AGRO<span className="text-green-600">KONGO</span>
              </span>
            </Link>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
            <Link href="/" className={isActive("/")}>Início</Link>
            <Link href="/mercado" className={isActive("/mercado")}>Mercado</Link>
            <Link href="/sobre" className={isActive("/sobre")}>Sobre Nós</Link>
            <Link href="/contacto" className={isActive("/contacto")}>Contactos</Link>
            <Link href="/ajuda" className={isActive("/ajuda")}>Ajuda</Link>

            {user ? (
              <div className="relative ml-4">
                <button
                  onClick={() => setDropdownOpen(!dropdownOpen)}
                  className="flex items-center gap-2 text-sm font-medium text-gray-700 hover:text-green-600 focus:outline-none"
                >
                  <div className="h-9 w-9 rounded-full bg-green-100 flex items-center justify-center text-green-700 font-bold border border-green-200">
                    {user.foto_perfil ? (
                      <img src={`http://localhost:5000${user.foto_perfil}`} alt="Perfil" className="h-full w-full rounded-full object-cover" />
                    ) : (
                      user.nome.charAt(0)
                    )}
                  </div>
                  <span className="hidden lg:block">{user.nome.split(' ')[0]}</span>
                  <ChevronDown size={16} />
                </button>

                {/* Dropdown */}
                {dropdownOpen && (
                  <div className="absolute right-0 mt-2 w-56 bg-white rounded-xl shadow-2xl py-2 ring-1 ring-black ring-opacity-5 transform transition-all duration-200 ease-out origin-top-right">
                    <div className="px-4 py-3 border-b border-gray-100">
                      <p className="text-xs text-gray-500 uppercase">Conta</p>
                      <p className="text-sm font-medium text-gray-900 truncate">{user.email || user.telemovel}</p>
                    </div>

                    <Link href="/dashboard" className="flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-green-50 hover:text-green-700">
                      <LayoutDashboard size={18} className="mr-3" /> Dashboard
                    </Link>

                    {user.tipo === 'comprador' && (
                      <Link href="/comprador/minhas-compras" className="flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-green-50 hover:text-green-700">
                        <ShoppingBag size={18} className="mr-3" /> Minhas Compras
                      </Link>
                    )}

                    <Link href="/ajuda" className="flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-green-50 hover:text-green-700">
                      <HelpCircle size={18} className="mr-3" /> Suporte
                    </Link>

                    <button
                      onClick={handleLogout}
                      className="w-full flex items-center px-4 py-2 text-sm text-red-600 hover:bg-red-50"
                    >
                      <LogOut size={18} className="mr-3" /> Sair
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <Link href="/auth/login" className="text-gray-900 font-medium hover:text-green-600 transition">
                  Entrar
                </Link>
                <Link
                  href="/auth/registro"
                  className="bg-green-600 text-white px-5 py-2.5 rounded-full font-bold hover:bg-green-700 transition shadow-lg shadow-green-200"
                >
                  Registar
                </Link>
              </div>
            )}
          </div>

          {/* Mobile button */}
          <div className="flex items-center md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-gray-700 hover:text-green-600 focus:outline-none"
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-gray-100 absolute w-full shadow-xl">
          <div className="px-4 pt-2 pb-6 space-y-2">
            <Link href="/" className="block px-3 py-3 rounded-md text-base font-medium text-gray-700 hover:text-green-600 hover:bg-green-50">Início</Link>
            <Link href="/mercado" className="block px-3 py-3 rounded-md text-base font-medium text-gray-700 hover:text-green-600 hover:bg-green-50">Mercado</Link>
            <Link href="/sobre" className="block px-3 py-3 rounded-md text-base font-medium text-gray-700 hover:text-green-600 hover:bg-green-50">Sobre</Link>
            <Link href="/contacto" className="block px-3 py-3 rounded-md text-base font-medium text-gray-700 hover:text-green-600 hover:bg-green-50">Contactos</Link>

            {!user && (
              <div className="mt-4 pt-4 border-t border-gray-100 flex flex-col gap-3">
                <Link href="/auth/login" className="w-full text-center px-4 py-3 border border-gray-300 rounded-lg text-gray-700 font-medium">
                  Entrar
                </Link>
                <Link href="/auth/registro" className="w-full text-center px-4 py-3 bg-green-600 rounded-lg text-white font-bold">
                  Criar Conta
                </Link>
              </div>
            )}

            {user && (
               <div className="mt-4 pt-4 border-t border-gray-100">
                 <div className="flex items-center px-3 mb-4">
                    <div className="h-10 w-10 rounded-full bg-green-100 flex items-center justify-center text-green-700 font-bold">
                      {user.nome.charAt(0)}
                    </div>
                    <div className="ml-3">
                      <div className="text-base font-medium leading-none text-gray-800">{user.nome}</div>
                      <div className="text-sm font-medium leading-none text-gray-500 mt-1">{user.email}</div>
                    </div>
                 </div>
                 <Link href="/dashboard" className="block px-3 py-2 rounded-md text-base font-medium text-gray-700 hover:bg-gray-100">Dashboard</Link>
                 <button onClick={handleLogout} className="block w-full text-left px-3 py-2 rounded-md text-base font-medium text-red-600 hover:bg-red-50">Sair</button>
               </div>
            )}
          </div>
        </div>
      )}
    </nav>
  );
}